function IsJsonString(str) {
  try {
    var input = JSON.parse( str );
  } catch (e) {
    action.stop();
    K('content[Valid JSON Format Message]').show();
    return false;
  }
  if (typeof input === "object" && input !== null) {
		return true;
	}
  action.stop();
  K('content[Valid JSON Format Message]').show();
  return false
}

