//Retrieve WebAPI listing
customCode.getWebApis = function(redisplay) {
  //clear existing options 
  K('field[WebAPI Selection]').options([]);

  //get new options
  var url = "/app/api/v1/webApis",
      path = "/webApis";
  if (K('field[Kapp Selection]').value() !== null) {
    url = "/app/api/v1/kapps/" + K('field[Kapp Selection]').value() + "/webApis";
    path = "/kapps/" + K('field[Kapp Selection]').value() + "/webApis";
  }
  //Store the path
  K('field[WebAPI Path]').value(path);

  $.ajax({
    url: url,
  })
  .done(function(result){
    var menuOptions = [];
    $.each(result['webApis'],function(i,v){
      menuOptions.push({"label":v.slug,"value":v.slug});
      K('field[WebAPI Selection]').options(menuOptions);
			// This is required because the Platform bridge doesn't support WebAPIs and 
      // they have to be retrieved from an ajax call.
      // Without this logic, the WebAPI Selection field will be cleared.
      if ( redisplay && K('field[WebAPI URL]').value() !== null ) {
        var webApiParts = K('field[WebAPI URL]').value().split("/");
        K('field[WebAPI Selection]').value(webApiParts[webApiParts.length - 1])
      }
    })
  })
  .fail(function(response){
    console.log("Couldn't retrieve WebAPI listing");
  })
}


